import{_ as n,o as a,c as e,a2 as o}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse(`{"title":"Variables Ownership vs Python GC","description":"The fundamental shift from Python's garbage-collected references to Rust's ownership model where every value has exactly one owner.","frontmatter":{"title":"Variables Ownership vs Python GC","description":"The fundamental shift from Python's garbage-collected references to Rust's ownership model where every value has exactly one owner."},"headers":[],"relativePath":"learn/linear/02-rust-for-python-developers/05-variables-ownership-vs-python-gc.md","filePath":"learn/linear/02-rust-for-python-developers/05-variables-ownership-vs-python-gc.md"}`),l={name:"learn/linear/02-rust-for-python-developers/05-variables-ownership-vs-python-gc.md"};function t(p,s,c,r,i,y){return a(),e("div",null,[...s[0]||(s[0]=[o(`<h1 id="variables-ownership-vs-python-gc" tabindex="-1">Variables Ownership vs Python GC <a class="header-anchor" href="#variables-ownership-vs-python-gc" aria-label="Permalink to &quot;Variables Ownership vs Python GC&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How Rust&#39;s ownership system replaces garbage collection with compile-time memory management</li><li>What move semantics mean and why assigning a variable in Rust can invalidate the original</li><li>How to think about scope and drop as the Rust equivalent of Python&#39;s reference counting and GC</li></ul></blockquote><p>This is the section that changes how you think about programming. Ownership is the concept that makes Rust unique, and it is the biggest mental shift you will make coming from Python. Everything in this section exists to answer one question: <em>who is responsible for freeing this memory, and when?</em></p><p>In Python, you never ask this question. The garbage collector handles it. In Rust, the compiler answers it at compile time, and the rules are surprisingly simple.</p><h2 id="how-python-manages-memory" tabindex="-1">How Python manages memory <a class="header-anchor" href="#how-python-manages-memory" aria-label="Permalink to &quot;How Python manages memory&quot;">​</a></h2><p>In Python, every value lives on the heap, and the runtime tracks how many variables point to it. When no variables point to a value anymore, the garbage collector frees it.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Python&#39;s memory model</span></span>
<span class="line"><span style="color:#CDD6F4;">a </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 2</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">]</span><span style="color:#6C7086;font-style:italic;">   # A list is created on the heap. a points to it. refcount = 1</span></span>
<span class="line"><span style="color:#CDD6F4;">b </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> a            </span><span style="color:#6C7086;font-style:italic;"># b also points to the same list. refcount = 2</span></span>
<span class="line"><span style="color:#CDD6F4;">a </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> None</span><span style="color:#6C7086;font-style:italic;">         # a no longer points to the list. refcount = 1</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># b still points to the list, so it stays alive</span></span>
<span class="line"><span style="color:#CDD6F4;">b </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> None</span><span style="color:#6C7086;font-style:italic;">         # refcount = 0. The garbage collector frees the list.</span></span></code></pre></div><p>This model is invisible and convenient. You create objects, pass them around, and they get cleaned up automatically. The downside is:</p><ul><li><strong>Non-deterministic cleanup</strong> — you cannot predict exactly when memory is freed</li><li><strong>GC pauses</strong> — the garbage collector periodically scans for cycles, which pauses your program</li><li><strong>Memory overhead</strong> — every object carries a reference count and type information</li></ul><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Here is a subtle Python bug that ownership prevents. In Python, <code>a</code> and <code>b</code> point to the <em>same</em> list:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">a </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 2</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">b </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> a</span></span>
<span class="line"><span style="color:#CDD6F4;">b</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">append</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">4</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">a</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # [1, 2, 3, 4] — surprise! a changed because b is the same object</span></span></code></pre></div><p>This shared mutable state is a major source of bugs. In Rust, when you assign <code>b = a</code>, the value <em>moves</em> to <code>b</code> and <code>a</code> becomes invalid. There is no shared mutable state by default. To share, you must explicitly borrow (next section) or clone (explicit copy).</p></div><h2 id="rust-s-ownership-rules" tabindex="-1">Rust&#39;s ownership rules <a class="header-anchor" href="#rust-s-ownership-rules" aria-label="Permalink to &quot;Rust&#39;s ownership rules&quot;">​</a></h2><p>Rust has three ownership rules. They are simple, but their consequences are profound:</p><ol><li><strong>Every value has exactly one owner</strong> — a variable that holds the value</li><li><strong>There can only be one owner at a time</strong> — assigning to another variable <em>moves</em> ownership</li><li><strong>When the owner goes out of scope, the value is dropped</strong> — memory is freed immediately</li></ol><p>Let&#39;s see each rule in action.</p><h3 id="rule-1-every-value-has-one-owner" tabindex="-1">Rule 1: Every value has one owner <a class="header-anchor" href="#rule-1-every-value-has-one-owner" aria-label="Permalink to &quot;Rule 1: Every value has one owner&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> name </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Agent&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // \`name\` owns this String</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">              // \`name\` is still the owner, we can use it</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// \`name\` goes out of scope here — the String is dropped and its memory is freed</span></span></code></pre></div><h3 id="rule-2-moving-ownership" tabindex="-1">Rule 2: Moving ownership <a class="header-anchor" href="#rule-2-moving-ownership" aria-label="Permalink to &quot;Rule 2: Moving ownership&quot;">​</a></h3><p>This is where Python developers get surprised:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> a </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> b </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // ownership MOVES from a to b</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // println!(&quot;{}&quot;, a);</span><span style="color:#6C7086;font-style:italic;">  // ERROR: value used after move</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> b</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">     // OK — b is the owner now</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>When you write <code>let b = a;</code>, Rust does <em>not</em> make a copy of the string. It does not increment a reference count. It <em>moves</em> the ownership from <code>a</code> to <code>b</code>. After the move, <code>a</code> is no longer valid. Trying to use <code>a</code> is a compile-time error.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, <code>b = a</code> creates a second reference to the same object. Both <code>a</code> and <code>b</code> are valid and point to the same data. In Rust, <code>b = a</code> transfers ownership. After the move, only <code>b</code> is valid. Think of it like handing someone a physical book — you had it, now they have it, and you cannot read a book you no longer hold.</p></div><h3 id="why-does-this-feel-so-different" tabindex="-1">Why does this feel so different? <a class="header-anchor" href="#why-does-this-feel-so-different" aria-label="Permalink to &quot;Why does this feel so different?&quot;">​</a></h3><p>Let&#39;s trace through the mental model:</p><p><strong>Python — reference counting:</strong></p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">a </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#6C7086;font-style:italic;">    # Object created, a references it (refcount=1)</span></span>
<span class="line"><span style="color:#CDD6F4;">b </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> a          </span><span style="color:#6C7086;font-style:italic;"># b also references it (refcount=2)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Both a and b are valid. The object exists until refcount hits 0.</span></span></code></pre></div><p><strong>Rust — ownership transfer:</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> a </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;hello&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // a owns the String</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> b </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">                       // ownership moves to b. a is invalidated.</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Only b is valid now. The String exists until b goes out of scope.</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> b</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This feels restrictive, but it gives you a powerful guarantee: at any point in your program, there is <em>exactly one</em> variable responsible for each piece of data. No confusion about who &quot;owns&quot; what. No surprise mutations through aliases.</p><h3 id="rule-3-scope-based-cleanup-drop" tabindex="-1">Rule 3: Scope-based cleanup (drop) <a class="header-anchor" href="#rule-3-scope-based-cleanup-drop" aria-label="Permalink to &quot;Rule 3: Scope-based cleanup (drop)&quot;">​</a></h3><p>When a variable goes out of scope, Rust immediately runs its <em>drop</em> code, freeing any resources it holds. This is deterministic — you know exactly when cleanup happens.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> data </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;temporary&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> data</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }</span><span style="color:#6C7086;font-style:italic;">  // \`data\` is dropped RIGHT HERE — memory freed immediately</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // data is not accessible here — it no longer exists</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;data was already freed&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python has a similar concept with context managers:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">with</span><span style="color:#FAB387;font-style:italic;"> open</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;file.txt&quot;</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> f</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    data </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> f</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">read</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># f is closed here (guaranteed by __exit__)</span></span></code></pre></div><p>In Rust, <em>every</em> resource gets this deterministic cleanup behavior automatically, not just things you wrap in <code>with</code> blocks. File handles, network connections, memory allocations — they are all freed the instant their owner goes out of scope. No <code>with</code> statement needed.</p></div><h2 id="move-semantics-in-functions" tabindex="-1">Move semantics in functions <a class="header-anchor" href="#move-semantics-in-functions" aria-label="Permalink to &quot;Move semantics in functions&quot;">​</a></h2><p>Ownership also transfers when you pass values to functions:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> print_greeting</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello, </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span><span style="color:#6C7086;font-style:italic;">  // \`name\` is dropped here — the String is freed</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> my_name </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Alice&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    print_greeting</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">my_name</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // ownership moves into the function</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // println!(&quot;{}&quot;, my_name);</span><span style="color:#6C7086;font-style:italic;">  // ERROR: my_name was moved</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Passing <code>my_name</code> to <code>print_greeting</code> moves ownership into the function&#39;s parameter. After the call, <code>my_name</code> is invalid. The function now owns the data and will free it when the function returns.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, passing a value to a function just copies the reference:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> print_greeting</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">name</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    print</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;font-style:italic;">f</span><span style="color:#A6E3A1;">&quot;Hello, </span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">name</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">my_name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Alice&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">print_greeting</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">my_name</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">my_name</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # Still works — Python just passed a reference</span></span></code></pre></div><p>In Rust, you &quot;give away&quot; the value when you pass it. If you want to keep using it after the function call, you need to either <em>borrow</em> it (next section) or <em>clone</em> it (make an explicit copy).</p></div><h2 id="copy-vs-move-the-simple-types-exception" tabindex="-1">Copy vs Move: the simple types exception <a class="header-anchor" href="#copy-vs-move-the-simple-types-exception" aria-label="Permalink to &quot;Copy vs Move: the simple types exception&quot;">​</a></h2><p>Not everything moves. Simple, fixed-size types that live on the stack are <em>copied</em> instead of moved:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> x</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> i32</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 42</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> y </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> x</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // x is COPIED, not moved (integers implement Copy)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;x=</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">, y=</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> x</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> y</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // Both are valid!</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> a </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> b </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // booleans are also Copy</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;a=</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">, b=</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> b</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // Both are valid!</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Types that implement the <code>Copy</code> trait — integers, floats, booleans, characters, and tuples of Copy types — are automatically copied on assignment. These types are small, cheap to copy, and have no resources to manage.</p><p><code>String</code>, <code>Vec</code>, and other heap-allocated types do <em>not</em> implement <code>Copy</code>. They <em>move</em> on assignment because copying them would be expensive (duplicating heap data).</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Copy types — assignment copies</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> x </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 42</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">        // i32 → Copy</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> y </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> x</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">         // y is a copy, x still valid</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#9399B2;"> {}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> x</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> y</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Move types — assignment moves</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s1 </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;hello&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // String → Move</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s2 </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> s1</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">                     // s1 is moved to s2, s1 invalid</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // println!(&quot;{}&quot;, s1);</span><span style="color:#6C7086;font-style:italic;">  // ERROR: use of moved value</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s2</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h2 id="explicit-cloning" tabindex="-1">Explicit cloning <a class="header-anchor" href="#explicit-cloning" aria-label="Permalink to &quot;Explicit cloning&quot;">​</a></h2><p>When you genuinely need a copy of heap data, use <code>.clone()</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s1 </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s2 </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> s1</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">  // Deep copy — both s1 and s2 are valid</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;s1=</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">, s2=</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s1</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s2</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p><code>clone()</code> in Rust is like <code>copy.deepcopy()</code> in Python. The key difference is that Python makes shallow copies by default (<code>b = a</code> copies the reference), while Rust moves by default. In Rust, you opt into copying with <code>.clone()</code>. In Python, you opt into deep copying with <code>copy.deepcopy()</code>. The defaults are inverted, which pushes Rust developers toward sharing data through borrowing (zero-cost) rather than copying (expensive).</p></div><h2 id="returning-ownership" tabindex="-1">Returning ownership <a class="header-anchor" href="#returning-ownership" aria-label="Permalink to &quot;Returning ownership&quot;">​</a></h2><p>Functions can return ownership back to the caller:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> create_greeting</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">name</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> greeting </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello, </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    greeting  </span><span style="color:#6C7086;font-style:italic;">// ownership of the String moves to the caller</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> create_greeting</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Alice&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> message</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // message owns the String now</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>You can also take ownership in a function and return it:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> add_exclamation</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">mut</span><span style="color:#EBA0AC;"> text</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#9399B2;">&#39;</span><span style="color:#A6E3A1;">!</span><span style="color:#9399B2;">&#39;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    text  </span><span style="color:#6C7086;font-style:italic;">// return ownership to the caller</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> greeting </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> excited </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> add_exclamation</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">greeting</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // greeting is moved, but excited holds the modified value</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> excited</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // &quot;Hello!&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This pattern of &quot;take ownership, modify, return&quot; works but is verbose. The next section introduces <em>borrowing</em>, which lets you access data without taking ownership — a much more ergonomic approach.</p><h2 id="the-ownership-mental-model" tabindex="-1">The ownership mental model <a class="header-anchor" href="#the-ownership-mental-model" aria-label="Permalink to &quot;The ownership mental model&quot;">​</a></h2><p>Here is a summary you can use as a reference:</p><table tabindex="0"><thead><tr><th>Situation</th><th>Python</th><th>Rust</th></tr></thead><tbody><tr><td>Assign <code>b = a</code> (heap type)</td><td>Both <code>a</code> and <code>b</code> reference the same object</td><td><code>a</code> is moved to <code>b</code>; <code>a</code> is invalid</td></tr><tr><td>Assign <code>b = a</code> (int/bool)</td><td>Both valid (same object ref)</td><td>Both valid (value is copied)</td></tr><tr><td>Pass to function</td><td>Reference copied; caller can still use value</td><td>Ownership moves; caller cannot use value</td></tr><tr><td>Return from function</td><td>Reference returned</td><td>Ownership returned to caller</td></tr><tr><td>Variable goes out of scope</td><td>Refcount decremented; GC may collect later</td><td>Value dropped immediately; memory freed</td></tr><tr><td>Explicit copy</td><td><code>copy.deepcopy(a)</code></td><td><code>a.clone()</code></td></tr></tbody></table><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Every value in Rust has exactly one owner, and when that owner goes out of scope, the value is immediately freed — no garbage collector needed</li><li>Assignment of heap types (<code>String</code>, <code>Vec</code>) <em>moves</em> ownership, making the original variable invalid — this prevents aliased mutable state</li><li>Simple stack types (integers, booleans, floats) implement <code>Copy</code> and are duplicated on assignment — both variables remain valid</li><li>Use <code>.clone()</code> when you genuinely need a deep copy, but prefer borrowing (next section) for zero-cost data access</li><li>Rust&#39;s ownership model trades the convenience of automatic reference counting for compile-time guarantees about memory safety and deterministic resource cleanup</li></ul>`,58)])])}const u=n(l,[["render",t]]);export{h as __pageData,u as default};
